import { ORDINAL_DATATYPE } from '../../../../core/datatype-constants';

export function ApplyFilterOnPlot(mouse, data) {
    let manager = this,
        { chart, options } = manager,
        { config, dataType } = options,
        { ranges, filter } = config,
        point = ranges[data.point];

    if (!filter.enabled || (isAllDisabled(ranges) && !point.disabled)) {
        return;
    }

    point.disabled = !point.disabled;
    let filtered = ranges.filter(range => !range.disabled);

    if (dataType === ORDINAL_DATATYPE) {
        filtered = filtered.map(d => d[0]);
    }

    config.filter.range = filtered;
    chart.plot.renderer.draw(true);
}

function isAllDisabled(ranges) {
    var disabledEle = ranges.filter(range => range.disabled);

    return disabledEle.length == ranges.length - 1;
}
